#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(long long*)a - *(long long*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, C;
        scanf("%d %d %d", &N, &K, &C);
        long long arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &arr[i]);
        }
        qsort(arr, N, sizeof(long long), compare);
        int steps = 0;
        int i = 0;
        while (i < N) {
            int j = i + 1;
            int count = 1;
            while (j < N && count < K && arr[j] >= arr[j - 1] * C) {
                count++;
                j++;
            }
            steps++;
            i = j;
        }
        printf("%d\n", steps);
    }
    return 0;
}

