import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int C = sc.nextInt();
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextLong();
            }
            Arrays.sort(arr);
            int steps = 0;
            int i = 0;
            while (i < N) {
                int j = i + 1;
                int count = 1;
                while (j < N && count < K && arr[j] >= arr[j - 1] * C) {
                    count++;
                    j++;
                }
                steps++;
                i = j;
            }
            System.out.println(steps);
        }
    }
}

